diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 48055ad6ea7e..48f158a35b54 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5745,6 +5745,28 @@ static bool casesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases) {
   return true;
 }

+/// Check if the cases NOT in the given list but within [MinVal, MaxVal) are
+/// contiguous. This is used when the explicit cases are not contiguous but
+/// the implicit (default) cases within the argument's range are.
+static bool missingCasesAreContiguous(SmallVectorImpl<ConstantInt *> &Cases,
+                                       const APInt &MinVal, const APInt &MaxVal,
+                                       SmallVectorImpl<ConstantInt *> &Missing) {
+  // Build the list of missing values within [MinVal, MaxVal).
+  for (APInt Val = MinVal; Val.ult(MaxVal); ++Val) {
+    ConstantInt *CI = ConstantInt::get(Cases[0]->getContext(), Val);
+    // Check if Val is in Cases.
+    bool found = false;
+    for (auto *C : Cases)
+      if (C->getValue() == Val) {
+        found = true;
+        break;
+      }
+    if (!found)
+      Missing.push_back(CI);
+  }
+  return Missing.size() >= 1 && casesAreContiguous(Missing);
+}
